document.addEventListener("DOMContentLoaded",()=>{const e=document.getElementById("menu-toggle"),t=document.getElementById("primary-navigation");if(!e||!t)return;e.addEventListener("click",()=>{const n=e.getAttribute("aria-expanded")==="true";e.setAttribute("aria-expanded",String(!n)),t.classList.toggle("is-open",!n)}),t.addEventListener("click",n=>{if(!(n.target instanceof Element)||!n.target.closest("a"))return;e.setAttribute("aria-expanded","false"),t.classList.remove("is-open")})})